SET @OGUID := 35000000; -- Set by TDB team (Need 285)
SET @EVENT := 24;

DELETE FROM `gameobject` WHERE `guid` BETWEEN @OGUID+0 AND @OGUID+284;

-- Booty Bay brewfest spawns should be visible during the Brashtide attack (phase 239)
UPDATE `gameobject` SET `phaseUseFlags`=1 WHERE `guid` BETWEEN @OGUID+0 AND @OGUID+83;

DELETE FROM `game_event_gameobject` WHERE `guid` BETWEEN @OGUID+0 AND @OGUID+284 AND `eventEntry`=@EVENT;
